{
  "summary": "A procedural UI element consisting of a central heart shape with a layered radial glow. The effect uses a primary heart graphic and a secondary 'aura' graphic that pulses in scale and alpha to create a soft, rhythmic breathing effect suitable for a score background or life indicator.",
  "duration_ms": 2000,
  "palette": [
    "#FF1493",
    "#FF69B4",
    "#FFB6C1",
    "#FFFFFF"
  ],
  "particle_config": {
    "count": 0,
    "note": "This is a static UI component with procedural animation rather than a particle emitter. It uses layered Graphics objects for the glow effect."
  },
  "typescript": "class GlowingHeartUI extends Phaser.GameObjects.Container {
  private heart: Phaser.GameObjects.Graphics;
  private glow: Phaser.GameObjects.Graphics;

  constructor(scene: Phaser.Scene, x: number, y: number, size: number = 100) {
    super(scene, x, y);

    // Create the outer glow layer
    this.glow = scene.add.graphics();
    this.drawHeart(this.glow, size * 1.2, 0xFF69B4);
    this.glow.setAlpha(0.4);
    this.glow.setBlendMode(Phaser.BlendModes.ADD);

    // Create the main heart layer
    this.heart = scene.add.graphics();
    this.drawHeart(this.heart, size, 0xFF1493);

    this.add([this.glow, this.heart]);
    scene.add.existing(this);

    // Pulsing animation
    scene.tweens.add({
      targets: this.glow,
      scale: 1.4,
      alpha: 0.1,
      duration: 1000,
      yoyo: true,
      repeat: -1,
      ease: 'Sine.easeInOut'
    });

    scene.tweens.add({
      targets: this.heart,
      scale: 1.05,
      duration: 1000,
      yoyo: true,
      repeat: -1,
      ease: 'Sine.easeInOut'
    });
  }

  private drawHeart(graphics: Phaser.GameObjects.Graphics, size: number, color: number) {
    const s = size / 2;
    graphics.clear();
    graphics.fillStyle(color, 1);
    graphics.beginPath();
    graphics.moveTo(0, s * 0.3);
    graphics.cubicCurveTo(-s, -s, -s * 1.5, s * 0.5, 0, s * 1.5);
    graphics.cubicCurveTo(s * 1.5, s * 0.5, s, -s, 0, s * 0.3);
    graphics.closePath();
    graphics.fillPath();

    // Add a soft white highlight
    graphics.fillStyle(0xFFFFFF, 0.3);
    graphics.fillCircle(-s * 0.3, -s * 0.1, s * 0.2);
  }
}"
}
